// Obtener token de credenciales
const token = $credentials.telegramApi.accessToken;

if (!token) {
  throw new Error('Token de Telegram no configurado. Verifica las credenciales.');
}

// Inicializar offset si no existe
if (!$workflow.staticData.offset) {
  $workflow.staticData.offset = 0;
}

const offset = $workflow.staticData.offset;

console.log(`[Telegram] Obteniendo updates con offset: ${offset}`);

try {
  // Pedir actualizaciones a Telegram
  const response = await fetch(
    `https://api.telegram.org/bot${token}/getUpdates?offset=${offset}&timeout=5&allowed_updates=["message"]`,
    { 
      method: 'GET',
      headers: {
        'Content-Type': 'application/json'
      }
    }
  );

  if (!response.ok) {
    throw new Error(`HTTP ${response.status}: ${response.statusText}`);
  }

  const data = await response.json();

  if (!data.ok) {
    throw new Error(`Telegram API Error: ${data.description || 'Unknown error'}`);
  }

  // Si no hay mensajes, retornar vacío
  if (!data.result || data.result.length === 0) {
    console.log('[Telegram] No hay nuevos mensajes');
    return [];
  }

  console.log(`[Telegram] Recibidos ${data.result.length} updates`);

  // Procesar cada mensaje
  const mensajes = [];
  let maxUpdateId = offset;

  for (const update of data.result) {
    // Actualizar offset para no procesar el mismo mensaje dos veces
    if (update.update_id > maxUpdateId) {
      maxUpdateId = update.update_id;
    }

    // Solo procesar si tiene mensaje de texto
    if (update.message && update.message.text) {
      mensajes.push({
        json: {
          update_id: update.update_id,
          chat_id: update.message.chat.id,
          texto: update.message.text,
          usuario: update.message.from.first_name || 'Usuario',
          usuario_id: update.message.from.id,
          message_id: update.message.message_id
        }
      });

      console.log(`[Telegram] Mensaje recibido: ${update.message.text} de ${update.message.from.first_name}`);
    }
  }

  // Guardar el último update_id procesado
  if (maxUpdateId > offset) {
    $workflow.staticData.offset = maxUpdateId + 1;
    console.log(`[Telegram] Offset actualizado a: ${$workflow.staticData.offset}`);
  }

  return mensajes;

} catch (error) {
  console.error('[Telegram] Error obteniendo mensajes:', error.message);
  // No lanzar error, solo retornar vacío para que el workflow continúe
  return [];
}

const chatId = $input.item.json.chat_id;
const texto = $input.item.json.texto;
const usuario = $input.item.json.usuario;
const token = $credentials.telegramApi.accessToken;

if (!token) {
  throw new Error('Token de Telegram no configurado');
}

// Decidir qué responder según el comando
let respuesta = '';

if (texto === '/start' || texto.startsWith('/start')) {
  respuesta = `🎉 ¡Hola ${usuario}!

✨ Soy el Bot de Gestión de Aulas UIDE.

📝 Comandos disponibles:
• /start - Mensaje de bienvenida
• /ayuda - Ver ayuda
• /estado - Ver estado del sistema
• /info - Información del bot

¡Escribe un comando para comenzar!`;

} else if (texto === '/ayuda' || texto === '/help' || texto.startsWith('/ayuda') || texto.startsWith('/help')) {
  respuesta = `📚 AYUDA DEL BOT

🔹 /start - Inicia el bot
🔹 /ayuda - Muestra esta ayuda
🔹 /estado - Estado del sistema
🔹 /info - Información del bot

💡 Tip: Todos los comandos empiezan con /`;

} else if (texto === '/estado' || texto.startsWith('/estado')) {
  const ahora = new Date().toLocaleString('es-EC', { timeZone: 'America/Guayaquil' });
  respuesta = `📊 ESTADO DEL SISTEMA

✅ Bot: Operativo
✅ Conexión: Activa
🕐 Hora: ${ahora}

✨ Todo funcionando correctamente!`;

} else if (texto === '/info' || texto.startsWith('/info')) {
  respuesta = `ℹ️ INFORMACIÓN

🤖 Bot: Gestión Aulas UIDE
📍 Modo: Local (Polling)
⚡ Versión: 1.0.0
🔄 Actualización: Cada 10 seg

Desarrollado para UIDE 🎓`;

} else {
  respuesta = `🤔 No entiendo "${texto}"

Prueba con:
• /start
• /ayuda
• /estado
• /info`;
}

// Enviar respuesta
console.log(`[Telegram] Enviando respuesta a chat ${chatId}: ${respuesta.substring(0, 50)}...`);

try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      chat_id: chatId,
      text: respuesta,
      parse_mode: 'Markdown'
    })
  });

  const result = await response.json();

  if (!result.ok) {
    console.error(`[Telegram] Error enviando mensaje: ${result.description}`);
    return [{ json: { enviado: false, error: result.description } }];
  }

  console.log(`[Telegram] Mensaje enviado exitosamente a chat ${chatId}`);
  return [{ json: { enviado: true, comando: texto, chat_id: chatId } }];

} catch (error) {
  console.error(`[Telegram] Error: ${error.message}`);
  return [{ json: { enviado: false, error: error.message } }];
}

// Responder a mensajes que no son comandos
const chatId = $input.item.json.chat_id;
const texto = $input.item.json.texto;
const token = $credentials.telegramApi.accessToken;

const respuesta = `💬 Recibí tu mensaje: "${texto}"

Pero solo respondo a comandos que empiezan con /

Prueba con:
• /start
• /ayuda
• /estado`;

try {
  await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: chatId,
      text: respuesta
    })
  });

  return [{ json: { procesado: true } }];
} catch (error) {
  return [{ json: { procesado: false, error: error.message } }];
}
